class Solution:
    def goodTriplets(self, nums1, nums2):
        n = len(nums1)
        pos2 = [0] * n
        for idx, v in enumerate(nums2):
            pos2[v] = idx
        seq = [pos2[v] for v in nums1]

        def bit_update(tree, i, size):
            i += 1
            while i <= size:
                tree[i] += 1
                i += i & (-i)

        def bit_query(tree, i):
            if i < 0:
                return 0
            i += 1
            s = 0
            while i > 0:
                s += tree[i]
                i -= i & (-i)
            return s

        left = [0] * n
        tree1 = [0] * (n + 1)
        for j in range(n):
            left[j] = bit_query(tree1, seq[j] - 1)
            bit_update(tree1, seq[j], n)

        right = [0] * n
        tree2 = [0] * (n + 1)
        inserted = 0
        for j in range(n - 1, -1, -1):
            right[j] = inserted - bit_query(tree2, seq[j])
            bit_update(tree2, seq[j], n)
            inserted += 1

        return sum(left[j] * right[j] for j in range(n))

