var goodTriplets = function(nums1, nums2) {
    const n = nums1.length;
    const pos2 = new Array(n);
    for (let i = 0; i < n; i++) pos2[nums2[i]] = i;
    const seq = nums1.map(v => pos2[v]);

    const bitUpdate = (tree, i, size) => {
        i += 1;
        while (i <= size) {
            tree[i] += 1;
            i += i & (-i);
        }
    };
    const bitQuery = (tree, i) => {
        if (i < 0) return 0;
        i += 1;
        let s = 0;
        while (i > 0) {
            s += tree[i];
            i -= i & (-i);
        }
        return s;
    };

    const left = new Array(n).fill(0);
    const tree1 = new Array(n + 1).fill(0);
    for (let j = 0; j < n; j++) {
        left[j] = bitQuery(tree1, seq[j] - 1);
        bitUpdate(tree1, seq[j], n);
    }

    const right = new Array(n).fill(0);
    const tree2 = new Array(n + 1).fill(0);
    let inserted = 0;
    for (let j = n - 1; j >= 0; j--) {
        right[j] = inserted - bitQuery(tree2, seq[j]);
        bitUpdate(tree2, seq[j], n);
        inserted++;
    }

    let total = 0;
    for (let j = 0; j < n; j++) total += left[j] * right[j];
    return total;
};
